/**
 * Get all teams for a club by dbuId.
 * Returns an array of { ageGroup, birthYear, gender, count } objects.
 */
export function getTeams(dbuId) {
  return teams[dbuId]?.teams ?? [];
}

/**
 * Get all clubs that have at least one team for a given age group.
 * @param {string} ageGroup — e.g. 'U10', 'U12', 'Senior'
 */
export function getClubsByAgeGroup(ageGroup) {
  return Object.entries(teams)
    .filter(([, v]) => v.teams.some(t => t.ageGroup === ageGroup))
    .map(([dbuId, v]) => ({ dbuId: Number(dbuId), name: v.name }));
}

/**
 * Get all clubs that have teams of a given gender.
 * @param {string} gender — 'drenge' | 'piger'
 */
export function getClubsByGender(gender) {
  return Object.entries(teams)
    .filter(([, v]) => v.teams.some(t => t.gender === gender))
    .map(([dbuId, v]) => ({ dbuId: Number(dbuId), name: v.name }));
}

/**
 * Get all clubs that have teams matching both age group and gender.
 */
export function findClubs({ ageGroup, gender } = {}) {
  return Object.entries(teams)
    .filter(([, v]) => v.teams.some(t =>
      (!ageGroup || t.ageGroup === ageGroup) &&
      (!gender   || t.gender   === gender)
    ))
    .map(([dbuId, v]) => ({ dbuId: Number(dbuId), name: v.name }));
}
